UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Consumptieaardappel", "locatie": "Binnen", "toepassingsmethode": "Ruimtebehandeling", "dosering": "0.01 L/m³", "opmerkingen": ["Toepassingsgebied: Consumptieaardappel voor versgebruik\n\nDosering middel per toepassing: 0,002-0,01 L/m3 ( 2-10 ppm). De dosering moet geleidelijk opgebouwd worden tot de maximale dosering. Een continue toepassing van de laagste dosering geeft onvoldoende werkzaamheid. Maximaal aantal toepassingen: 1 x continue\ntoepassing direct na opslag."]}, {"gewas": "Consumptieaardappel", "locatie": "Binnen", "toepassingsmethode": "Ruimtebehandeling", "dosering": "0.01 L/m³", "opmerkingen": ["Toepassingsgebied: Consumptieaardappel voor gebruik als friet- en chipsaardappelen\n\nDosering middel per toepassing: 0,0001-0,01 L/m3 (0,1-10 ppm. De dosering moet geleidelijk opgebouwd worden tot de maximale dosering. Een continue toepassing van de laagste dosering geeft onvoldoende werkzaamheid. Maximaal aantal toepassingen: 1 x continue toepassing direct na opslag."]}]'::jsonb, last_synced_at = NOW() WHERE toelatingsnummer = '13828';
UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Appel, Japanse peer, Peer, Kweepeer, Mispel, Overige pitvruchten", "doelorganisme": "Echte meeldauw", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "0.15 L/ha", "maxToepassingen": 4, "veiligheidstermijn": "14 dagen", "interval": "min. 8 dagen", "opmerkingen": ["Dosering: 0,01-0,015% (10-15 ml middel per 100 liter water). Verlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden\nafgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen. \n\nMaximaal aantal toepassingen per 12 maanden: 2 maal per blok; 2 blokken per 12 maanden.\n\nMinimum interval tussen toepassingen in dagen: 8 dagen binnen een blok, 42 dagen tussen twee blokken."], "wCodes": ["W7"], "bbchVan": "55", "bbchTot": "87", "spuitvolumeMin": 500, "spuitvolumeMax": 1500, "intervalDagen": 8, "phiDagen": 14}, {"gewas": "Batavia, Bindsla, Eikenbladsla, Ijsbergsla, Kropsla, Krulsla, Lolla bionda, Lollo rosso, Pluksla (= babyleaf), Snijsla (= babyleaf)", "doelorganisme": "Rattenkeutelziekte, Sclerotiënrot, Smet, Bessenrot en meiziekte, Bewaarrot, Bloesemrot, Botrytis, Botrytis stengelziekte, Botrytis-neusrot, Echte meeldauw, Grauwe schimmel, Hartrot, Ruiziekte, Scheutsterfte, Smeul, Treurziekte, Vruchtrot, Vuur, Wortelrot", "locatie": "Bedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "0.5 L/ha", "maxToepassingen": 2, "veiligheidstermijn": "7 dagen", "interval": "min. 7 dagen", "opmerkingen": ["Verlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen.", {"sentenceNL": "Om het grondwater te beschermen geldt er voor deze toepassing een restrictie in grondwaterbeschermingsgebieden in de perio